-- ═══ Jude Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Jude', 1, 'kids', 1, 'Who wrote the book of Jude?', 'Jude, the servant of Jesus Christ and brother of James', 'The apostle Paul', 'The apostle John', 'King David', 'a', 'Jude 1:1 — "Jude, the servant of Jesus Christ, and brother of James."'),
('Jude', 1, 'kids', 2, 'What did Jude want to write about at first?', 'The common salvation', 'The end of the world', 'A new church building', 'His travels', 'a', 'Jude 1:3 — "when I gave all diligence to write unto you of the common salvation."'),
('Jude', 1, 'kids', 3, 'What does Jude say God is able to do for us?', 'Keep us from falling and present us faultless before His glory', 'Make us rich and famous', 'Give us everything we want', 'Make us never get sick', 'a', 'Jude 1:24 — "Now unto him that is able to keep you from falling, and to present you faultless before the presence of his glory with exceeding joy."'),
-- Teens
('Jude', 1, 'teens', 1, 'What did Jude urge believers to do?', 'Earnestly contend for the faith which was once delivered unto the saints', 'Build bigger churches', 'Move to Jerusalem', 'Stop meeting together', 'a', 'Jude 1:3 — "it was needful for me to write unto you, and exhort you that ye should earnestly contend for the faith which was once delivered unto the saints."'),
('Jude', 1, 'teens', 2, 'What three Old Testament examples of judgment does Jude mention?', 'Unbelieving Israel in the wilderness, the fallen angels, and Sodom and Gomorrha', 'The flood, the tower of Babel, and the plagues of Egypt', 'Cain, Balaam, and Korah only', 'Adam, Noah, and Abraham', 'a', 'Jude 1:5-7 mentions Israel''s unbelief, angels who kept not their first estate, and Sodom and Gomorrha.'),
('Jude', 1, 'teens', 3, 'What did Michael the archangel say when disputing with the devil about Moses'' body?', '"The Lord rebuke thee"', '"Get behind me, Satan"', '"I command you to leave"', '"You have no power here"', 'a', 'Jude 1:9 — "Michael the archangel… durst not bring against him a railing accusation, but said, The Lord rebuke thee."'),
('Jude', 1, 'teens', 4, 'What three wicked men does Jude compare the false teachers to?', 'Cain, Balaam, and Korah', 'Pharaoh, Goliath, and Jezebel', 'Nimrod, Esau, and Ahab', 'Saul, Absalom, and Haman', 'a', 'Jude 1:11 — "Woe unto them! for they have gone in the way of Cain, and ran greedily after the error of Balaam for reward, and perished in the gainsaying of Core."'),
('Jude', 1, 'teens', 5, 'What does Jude say believers should do to build themselves up?', 'Build yourselves up on your most holy faith, praying in the Holy Ghost', 'Study Greek philosophy', 'Follow the traditions of the elders', 'Withdraw from all society', 'a', 'Jude 1:20 — "building up yourselves on your most holy faith, praying in the Holy Ghost."'),
-- Adults
('Jude', 1, 'adults', 1, 'What does Jude say about the ungodly men who crept in unawares?', 'They turn the grace of God into lasciviousness and deny the only Lord God and our Lord Jesus Christ', 'They openly declared war on the church', 'They demanded payment for spiritual services', 'They claimed to be new apostles', 'a', 'Jude 1:4 — "turning the grace of our God into lasciviousness, and denying the only Lord God, and our Lord Jesus Christ."'),
('Jude', 1, 'adults', 2, 'What does Jude say about the angels who "kept not their first estate"?', 'God hath reserved them in everlasting chains under darkness unto the judgment of the great day', 'They were forgiven and restored', 'They became human beings', 'They rule over the nations of the earth', 'a', 'Jude 1:6 — "the angels which kept not their first estate, but left their own habitation, he hath reserved in everlasting chains under darkness unto the judgment of the great day."'),
('Jude', 1, 'adults', 3, 'How does Jude describe the false teachers using nature metaphors?', 'Spots in your feasts of charity, clouds without water, trees twice dead plucked up by the roots, raging waves of the sea, wandering stars', 'Green pastures, still waters, fruitful vines, and gentle breezes', 'Mighty oaks, deep rivers, and tall mountains', 'Sharp swords, strong shields, and polished arrows', 'a', 'Jude 1:12-13 — "spots in your feasts of charity… clouds they are without water… trees whose fruit withereth… raging waves of the sea… wandering stars."'),
('Jude', 1, 'adults', 4, 'What prophecy of Enoch does Jude quote?', '"Behold, the Lord cometh with ten thousands of his saints, to execute judgment upon all"', '"The day of the Lord shall come as a thief in the night"', '"Every knee shall bow and every tongue confess"', '"The sun shall be turned into darkness"', 'a', 'Jude 1:14-15 — "Behold, the Lord cometh with ten thousands of his saints, To execute judgment upon all."'),
('Jude', 1, 'adults', 5, 'What does Jude say about the false teachers'' speech and motives?', 'They are murmurers, complainers, walking after their own lusts; their mouth speaketh great swelling words, having men''s persons in admiration because of advantage', 'They speak softly and carry ancient scrolls', 'They quote Scripture accurately but live wickedly', 'They are silent infiltrators who never speak publicly', 'a', 'Jude 1:16 — "These are murmurers, complainers, walking after their own lusts; and their mouth speaketh great swelling words, having men''s persons in admiration because of advantage."'),
('Jude', 1, 'adults', 6, 'What did the apostles say would come in the last time?', 'Mockers who walk after their own ungodly lusts, who are sensual, having not the Spirit', 'Great earthquakes and famines', 'A new prophet greater than Moses', 'An army from the east', 'a', 'Jude 1:18-19 — "there should be mockers in the last time, who should walk after their own ungodly lusts. These be they who separate themselves, sensual, having not the Spirit."'),
('Jude', 1, 'adults', 7, 'What three-part strategy does Jude give for dealing with those in spiritual danger?', 'Have compassion on some making a difference; save others with fear, pulling them out of the fire; hate even the garment spotted by the flesh', 'Rebuke all equally, excommunicate the stubborn, and pray for the rest', 'Ignore them, pray for them, and fast for them', 'Confront them publicly, write letters about them, and avoid them', 'a', 'Jude 1:22-23 — "of some have compassion, making a difference: And others save with fear, pulling them out of the fire; hating even the garment spotted by the flesh."'),
('Jude', 1, 'adults', 8, 'What does the doxology in Jude 24-25 ascribe to God?', 'Glory, majesty, dominion, and power, both now and ever — and the ability to keep believers from falling and present them faultless', 'Only eternal life and forgiveness', 'Wisdom and knowledge alone', 'Victory over Rome and earthly kingdoms', 'a', 'Jude 1:24-25 — "Now unto him that is able to keep you from falling, and to present you faultless before the presence of his glory with exceeding joy, To the only wise God our Saviour, be glory and majesty, dominion and power, both now and ever."');
